sp_instance.placeholder_dimensions_script:
function evaluateConfig(options) {
    return {
        "mobile": {
            "height": "100%",
            "width": "100%"
        },
        "desktop": {
            "height": "100%",
            "width": "100%"
        },
        "tablet": {
            "height": "100%",
            "width": "100%"
        },
	title: gs.getMessage(options.title) || gs.getMessage('Quick links')
    };
}
